    11→#[derive(Debug, Deserialize)]
    12→pub struct CreateCardRequest {
    13→    pub id: String,
    14→    pub spec: String,
    15→    #[serde(default)]
    16→    pub team: Option<String>,
    17→    #[serde(default = "default_template")]
    18→    pub template: String,
    19→    #[serde(default)]
    20→    pub priority: Option<u32>,
    21→}
    22→
    23→fn default_template() -> String {
    24→    "implement".to_string()
    25→}
    26→
    27→#[derive(Clone)]
    28→struct AppState {
    29→    cards_dir: PathBuf,
    30→    token: Option<String>,
    31→}
    32→
    33→async fn post_cards_new(
    34→    State(state): State<Arc<AppState>>,
    35→    headers: axum::http::HeaderMap,
    36→    Json(req): Json<CreateCardRequest>,
    37→) -> impl IntoResponse {
    38→    // Optional token auth
    39→    if let Some(expected_token) = &state.token {
    40→        let auth = headers
    41→            .get("authorization")
    42→            .and_then(|v| v.to_str().ok())
    43→            .unwrap_or("");
    44→        let bearer = format!("Bearer {}", expected_token);
    45→        if auth != bearer {
    46→            return (
    47→                StatusCode::UNAUTHORIZED,
    48→                Json(serde_json::json!({"error": "unauthorized"})),
    49→            );
    50→        }
    51→    }
    52→
    53→    // Validate id
    54→    let id = req.id.trim().to_string();
    55→    if id.is_empty() {
    56→        return (
    57→            StatusCode::BAD_REQUEST,
    58→            Json(serde_json::json!({"error": "id cannot be empty"})),
    59→        );
    60→    }
    61→    if id.contains('/') || id.contains('\\') {
    62→        return (
    63→            StatusCode::BAD_REQUEST,
    64→            Json(serde_json::json!({"error": "id cannot contain path separators"})),
    65→        );
    66→    }
    67→
    68→    let template = req.template.trim().to_string();
    69→    if template.is_empty() {
    70→        return (
    71→            StatusCode::BAD_REQUEST,
    72→            Json(serde_json::json!({"error": "template cannot be empty"})),
    73→        );
    74→    }
    75→
    76→    let spec = req.spec.clone();
    77→    if spec.is_empty() {
    78→        return (
    79→            StatusCode::BAD_REQUEST,
    80→            Json(serde_json::json!({"error": "spec cannot be empty"})),
    81→        );
    82→    }
    83→
    84→    // Check for existing card (duplicate detection)
    85→    if crate::paths::find_card(&state.cards_dir, &id).is_some() {
    86→        return (
    87→            StatusCode::CONFLICT,
    88→            Json(serde_json::json!({"error": format!("card already exists: {}", id)})),
    89→        );
    90→    }
    91→
    92→    // Create the card (may still fail if card appears between check and create)
    93→    let result = cards::create_card(
    94→        &state.cards_dir,
    95→        &template,
    96→        &id,
    97→        Some(&spec),
    98→        req.team.as_deref(),
    99→    );
   100→
   101→    match result {
   102→        Ok(card_path) => {
   103→            if let Some(priority) = req.priority {
   104→                if let Ok(mut meta) = read_meta(&card_path) {
   105→                    meta.priority = Some(i64::from(priority));
   106→                    let _ = write_meta(&card_path, &meta);
   107→                }
   108→            }
   109→            let path_str = card_path.to_string_lossy().to_string();
   110→            (
   111→                StatusCode::CREATED,
   112→                Json(serde_json::json!({"id": id, "path": path_str})),
   113→            )
   114→        }
   115→        Err(e) => {
   116→            let msg = e.to_string();
   117→            if msg.contains("already exists") {
   118→                (
   119→                    StatusCode::CONFLICT,
   120→                    Json(serde_json::json!({"error": msg})),
   121→                )
   122→            } else if msg.contains("template not found")
   123→                || msg.contains("cannot be empty")
   124→                || msg.contains("path separator")
   125→            {
   126→                (
   127→                    StatusCode::BAD_REQUEST,
   128→                    Json(serde_json::json!({"error": msg})),
   129→                )
   130→            } else {
   131→                (
   132→                    StatusCode::INTERNAL_SERVER_ERROR,
   133→                    Json(serde_json::json!({"error": msg})),
   134→                )
   135→            }
   136→        }
   137→    }
   138→}
   139→
   140→fn log_request(method: &str, path: &str, status: u16) {
   141→    let ts = Utc::now().to_rfc3339();
   142→    println!("[{}] {} {} {}", ts, method, path, status);
   143→}
   144→
   145→async fn logged_post_cards_new(
   146→    state: State<Arc<AppState>>,
   147→    headers: axum::http::HeaderMap,
   148→    body: Json<CreateCardRequest>,
   149→) -> impl IntoResponse {
   150→    let resp = post_cards_new(state, headers, body).await;
   151→    let resp = resp.into_response();
   152→    log_request("POST", "/cards/new", resp.status().as_u16());
   153→    resp
   154→}
   155→
   156→pub async fn run_serve(cards_dir: PathBuf, host: &str, port: u16) -> anyhow::Result<()> {
   157→    let token = std::env::var("BOP_SERVE_TOKEN").ok();
   158→    if token.is_some() {
   159→        println!("BOP_SERVE_TOKEN set — token auth enabled");
   160→    }
   161→
   162→    let state = Arc::new(AppState { cards_dir, token });
   163→
   164→    let app = Router::new()
   165→        .route("/cards/new", post(logged_post_cards_new))
   166→        .with_state(state);
   167→
   168→    let bind_addr = format!("{}:{}", host, port);
   169→    let listener = TcpListener::bind(&bind_addr).await?;
   170→    println!("bop serve listening on http://{}", bind_addr);
   171→
   172→    axum::serve(listener, app)
   173→        .with_graceful_shutdown(shutdown_signal())
   174→        .await?;
   175→
   176→    Ok(())
   177→}
   178→
   179→async fn shutdown_signal() {
   180→    use tokio::signal;
   181→
   182→    let ctrl_c = async {
   183→        signal::ctrl_c()
   184→            .await
   185→            .expect("failed to install Ctrl+C handler");
   186→    };
   187→
   188→    #[cfg(unix)]
   189→    let terminate = async {
   190→        signal::unix::signal(signal::unix::SignalKind::terminate())
   191→            .expect("failed to install SIGTERM handler")
   192→            .recv()
   193→            .await;
   194→    };
   195→
   196→    #[cfg(not(unix))]
   197→    let terminate = std::future::pending::<()>();
   198→
   199→    tokio::select! {
   200→        _ = ctrl_c => {},
   201→        _ = terminate => {},
   202→    }
   203→
   204→    println!("\nbop serve shutting down");
   205→}
