    37→fn wait_for_server(port: u16, timeout: Duration) -> bool {
    38→    let addr = format!("127.0.0.1:{}", port);
    39→    let deadline = Instant::now() + timeout;
    40→    while Instant::now() < deadline {
    41→        if TcpStream::connect(&addr).is_ok() {
    42→            return true;
    43→        }
    44→        std::thread::sleep(Duration::from_millis(100));
    45→    }
    46→    false
    47→}
