    49→fn send_http_request(port: u16, body: &str, token: &str) -> String {
    50→    let addr = format!("127.0.0.1:{}", port);
    51→    let request = format!(
    52→        "POST /cards/new HTTP/1.1\r\nHost: {}\r\nContent-Type: application/json\r\nAuthorization: Bearer {}\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
    53→        addr,
    54→        token,
    55→        body.len(),
    56→        body
    57→    );
    58→    let mut stream = TcpStream::connect(&addr).expect("connect to serve");
    59→    stream.write_all(request.as_bytes()).expect("write request");
    60→    let mut response = String::new();
    61→    stream.read_to_string(&mut response).expect("read response");
    62→    response
    63→}
