   185→pub async fn run_serve(cards_dir: PathBuf, host: &str, port: u16) -> anyhow::Result<()> {
   186→    let token = match std::env::var("BOP_SERVE_TOKEN") {
   187→        Ok(t) => {
   188→            println!("BOP_SERVE_TOKEN set — using provided token");
   189→            t
   190→        }
   191→        Err(_) => {
   192→            // Generate a random 32-character token
   193→            let generated: String = rand::thread_rng()
   194→                .sample_iter(&Alphanumeric)
   195→                .take(32)
   196→                .map(char::from)
   197→                .collect();
   198→            println!("⚠️  BOP_SERVE_TOKEN not set — generated random token:");
   199→            println!("   {}", generated);
   200→            println!("   Use: curl -H 'Authorization: Bearer {}' ...", generated);
   201→            generated
   202→        }
   203→    };
   204→
   205→    let state = Arc::new(AppState { cards_dir, token });
   206→
   207→    let app = Router::new()
   208→        .route("/cards/new", post(logged_post_cards_new))
   209→        .layer(axum::extract::DefaultBodyLimit::max(65536))
   210→        .with_state(state);
   211→
   212→    let bind_addr = format!("{}:{}", host, port);
   213→    let listener = TcpListener::bind(&bind_addr).await?;
   214→    println!("bop serve listening on http://{}", bind_addr);
   215→
   216→    axum::serve(listener, app)
   217→        .with_graceful_shutdown(shutdown_signal())
   218→        .await?;
   219→
   220→    Ok(())
   221→}
