   223→async fn shutdown_signal() {
   224→    use tokio::signal;
   225→
   226→    let ctrl_c = async {
   227→        signal::ctrl_c()
   228→            .await
   229→            .expect("failed to install Ctrl+C handler");
   230→    };
   231→
   232→    #[cfg(unix)]
   233→    let terminate = async {
   234→        signal::unix::signal(signal::unix::SignalKind::terminate())
   235→            .expect("failed to install SIGTERM handler")
   236→            .recv()
   237→            .await;
   238→    };
   239→
   240→    #[cfg(not(unix))]
   241→    let terminate = std::future::pending::<()>();
   242→
   243→    tokio::select! {
   244→        _ = ctrl_c => {},
   245→        _ = terminate => {},
   246→    }
   247→
   248→    println!("\nbop serve shutting down");
   249→}
